from vex import verify

def safe_voice_agent(audio_input):
    user_text = get_realtime_transcript(audio_input)

    @verify([
        "response.appropriateness > 0.9",
        "latency.total < 500ms",
        "code_safety.passed",
        "response.toxicity < 0.1"
    ])
    def checked_run():
        return agent.run(user_text)

    response = checked_run()
    fast_tts(response)
    return response

def coherent_voice_loop(audio_input, history):
    user_text = get_realtime_transcript(audio_input)
    history_str = "\n".join([f"{h['role']}: {h['content']}" for h in history])

    @verify([
        "response.coherence > 0.85",
        "response.relevance(history_context) > 0.9",
        "latency.reasoning < 300ms"
    ])
    def verify_coherence():
        return agent.run(f"History: {history_str}\nUser: {user_text}")

    response = verify_coherence()
    history.append({"role": "assistant", "content": response})
    return response

